#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

int is_valid(int *arr, int N, int M, int K) {
    for (int i = 0; i <= N - K; i++) {
        int sum = 0;
        for (int j = i; j < i + K; j++) {
            sum += arr[j];
        }
        if (sum % M != 0) {
            return 0;
        }
    }
    return 1;
}

void backtrack(int *arr, int N, int M, int K, int start) {
    if (start == N) {
        if (is_valid(arr, N, M, K)) {
            for (int i = 0; i < N; i++) {
                printf("%d ", arr[i]);
            }
            printf("\n");
        }
    } else {
        for (int i = start; i < N; i++) {
            swap(&arr[start], &arr[i]);
            backtrack(arr, N, M, K, start + 1);
            swap(&arr[start], &arr[i]);
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
