import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int K = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int sum = 0;
            for (int i = 0; i < N; i++) {
                sum += arr[i];
            }
            if (sum % M != 0) {
                System.out.println(-1);
                continue;
            }
            backtrack(arr, N, M, K, 0);
        }
    }

    public static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    public static int is_valid(int[] arr, int N, int M, int K) {
        for (int i = 0; i <= N - K; i++) {
            int sum = 0;
            for (int j = i; j < i + K; j++) {
                sum += arr[j];
            }
            if (sum % M != 0) {
                return 0;
            }
        }
        return 1;
    }

    public static void backtrack(int[] arr, int N, int M, int K, int start) {
        if (start == N) {
            if (is_valid(arr, N, M, K) == 1) {
                for (int i = 0; i < N; i++) {
                    System.out.print(arr[i] + " ");
                }
                System.out.println();
            }
        } else {
            for (int i = start; i < N; i++) {
                swap(arr, start, i);
                backtrack(arr, N, M, K, start + 1);
                swap(arr, start, i);
            }
        }
    }
}

